example_bad:
fn first<'a, 'b>(x: &'a str, y: &'b str) -> &'a str {
    if x.len() > 0 { x } else { y } // Error: lifetime mismatch
}

fixes.code:
fn first<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > 0 { x } else { y }
}

fn first<'a, 'b: 'a>(x: &'a str, y: &'b str) -> &'a str {
    if x.len() > 0 { x } else { y }
}
